-- build_bank.lua -- Generate a C metadata bank from the global SQLite form DB.
--
-- This consumes build/stencil_bank/stencil_bank.sqlite from build_stencils.sh
-- and emits libsponbank.so exposing the sponbank.h descriptor/selector API.
-- Native stencil rows carry raw byte bodies plus explicit data/control relocs.

package.path = "../../../?.lua;../../../?/init.lua;src/?.lua;src/?/init.lua;" .. package.path

local cjson = require("cjson")
local sqlite3 = require("lsqlite3")
local Util = require("src.util")
local Constants = require("experiments.lua_interpreter_vm.src.constants")

local M = {}

local U32 = 4294967296

local function q(s) return Util.shell_quote(s) end

local function mkdir_p(path) assert(Util.mkdir_p(path), "mkdir failed: " .. tostring(path)) end

local function c_string(s)
  s = tostring(s or "")
  s = s:gsub("\\", "\\\\"):gsub('"', '\\"'):gsub("\n", "\\n"):gsub("\r", "\\r"):gsub("\t", "\\t")
  return '"' .. s .. '"'
end

local function as_c_u64_literal(x)
  if type(x) == "string" and x:match("^0x[%x]+ULL$") then return x end
  if type(x) == "string" and x:match("^0x[%x]+$") then return x .. "ULL" end
  return "0x0000000000000000ULL"
end

local function parse_sig_lohi(lit)
  local hex = tostring(lit or "0"):match("^0x([%x]+)ULL$") or tostring(lit or "0"):match("^0x([%x]+)$") or "0"
  hex = hex:lower()
  if #hex > 16 then hex = hex:sub(#hex - 15) end
  hex = string.rep("0", 16 - #hex) .. hex
  return tonumber(hex:sub(9, 16), 16) or 0, tonumber(hex:sub(1, 8), 16) or 0
end

local function popcount32(x)
  x = tonumber(x) or 0
  local n = 0
  while x > 0 do
    if x % 2 >= 1 then n = n + 1 end
    x = math.floor(x / 2)
  end
  return n
end

local function sig_pop(lit)
  local lo, hi = parse_sig_lohi(lit)
  return popcount32(lo) + popcount32(hi)
end

local function has_flag(flags, flag)
  flags, flag = tonumber(flags) or 0, tonumber(flag) or 0
  if flag == 0 then return true end
  return (math.floor(flags / flag) % 2) == 1
end

local OPCODE = {}
for name, value in pairs(Constants.Op or {}) do
  if type(name) == "string" and type(value) == "number" then OPCODE[name] = value end
end

local function op_name(op)
  if type(op) == "table" then return tostring(op.op or "") end
  return tostring(op or "")
end

local function packed_pattern(ops)
  local packed = 0
  for i, op in ipairs(ops or {}) do
    if i > 4 then break end
    local code = OPCODE[op_name(op)] or 0
    packed = packed + code * (256 ^ (i - 1))
  end
  return packed
end

local function selector_key_num(ops)
  local len = #(ops or {})
  return len * U32 + packed_pattern(ops)
end

local function selector_key_lit(ops)
  local len = #(ops or {})
  return string.format("0x%x%08xULL", len, packed_pattern(ops))
end

local function chunk_path(bank_src, name)
  if name:sub(1, 1) == "/" then return name end
  return bank_src .. "/" .. name
end

local function open_inc(out_dir, prefix, suffix)
  local path = string.format("%s/%s_%s.inc", out_dir, prefix, suffix)
  local f = assert(io.open(path, "wb"))
  return f, path
end

local function write_array_header(c, ctype, name, dummy)
  c:write("const ", ctype, " ", name, "[] = {\n")
  if dummy then c:write("  ", dummy, "\n") end
end

local function write_include(c, path)
  c:write('#include "', Util.basename(path), '"\n')
end

local function write_array_footer(c)
  c:write("};\n\n")
end

local function hex_to_bytes(hex)
  if type(hex) ~= "string" then return {} end
  local out = {}
  for pair in hex:gmatch("%x%x") do out[#out + 1] = tonumber(pair, 16) or 0 end
  return out
end

local function u(v) return tonumber(v) or 0 end
local function field(obj, name, default) local v = obj and obj[name]; if v == nil then return default end; return v end

local function emit_index(out_dir, shards, patterns, l0, total_stencils)
  local pattern_keys = {}
  for k, _ in pairs(patterns) do pattern_keys[#pattern_keys + 1] = k end
  table.sort(pattern_keys)

  local c_path = out_dir .. "/bank_index.c"
  local c = assert(io.open(c_path, "wb"))
  c:write("/* Generated by src/build_bank.lua. Native stencil bank index. */\n")
  c:write('#include "sponbank.h"\n#include <stddef.h>\n#include <stdint.h>\n\n')

  for _, s in ipairs(shards) do
    local i = s.chunk
    c:write(string.format("extern const SponStencilDesc spon_chunk_%d_stencils[];\n", i))
    c:write(string.format("extern const unsigned char spon_chunk_%d_data[];\n", i))
    c:write(string.format("extern const SponEndpointDesc spon_chunk_%d_endpoints[];\n", i))
    c:write(string.format("extern const SponLocationDesc spon_chunk_%d_locations[];\n", i))
    c:write(string.format("extern const SponDataReloc spon_chunk_%d_data_relocs[];\n", i))
    c:write(string.format("extern const SponControlReloc spon_chunk_%d_control_relocs[];\n", i))
    c:write(string.format("extern const SponSlotMapEntry spon_chunk_%d_slotmaps[];\n", i))
    c:write(string.format("extern const SponProjectionEntry spon_chunk_%d_projections[];\n", i))
    c:write(string.format("extern const SponDependencyDesc spon_chunk_%d_dependencies[];\n", i))
  end

  c:write([[

typedef struct {
  uint32_t first;
  uint32_t count;
  const SponStencilDesc *stencils;
  const unsigned char *data;
  const SponEndpointDesc *endpoints;
  const SponLocationDesc *locations;
  const SponDataReloc *data_relocs;
  const SponControlReloc *control_relocs;
  const SponSlotMapEntry *slotmaps;
  const SponProjectionEntry *projections;
  const SponDependencyDesc *dependencies;
} SponBankShard;

]])

  c:write("static const SponBankShard spon_shards[] = {\n")
  for _, s in ipairs(shards) do
    local i = s.chunk
    c:write(string.format("  {%d, %d, spon_chunk_%d_stencils, spon_chunk_%d_data, spon_chunk_%d_endpoints, spon_chunk_%d_locations, spon_chunk_%d_data_relocs, spon_chunk_%d_control_relocs, spon_chunk_%d_slotmaps, spon_chunk_%d_projections, spon_chunk_%d_dependencies},\n",
      s.first, s.count, i, i, i, i, i, i, i, i, i))
  end
  c:write("};\n")
  c:write(string.format("static const uint32_t spon_shard_count = %d;\n", #shards))
  c:write(string.format("static const uint32_t spon_stencil_count = %d;\n\n", total_stencils))

  c:write("static const SponStencilId spon_l0[256] = {\n")
  for i = 0, 255 do
    if i % 8 == 0 then c:write("  ") end
    c:write(tostring(l0[i] or 0))
    if i ~= 255 then c:write(", ") end
    if i % 8 == 7 then c:write("\n") end
  end
  c:write("};\n\n")

  c:write("typedef struct { uint64_t pattern_key; uint32_t start; uint32_t count; } PatternEntry;\n")
  c:write("static const SponStencilId spon_candidates[] = {\n")
  local candidate_count = 0
  for _, k in ipairs(pattern_keys) do
    local list = patterns[k]
    table.sort(list, function(a, b) return a > b end)
    for _, packed in ipairs(list) do
      local id = math.floor(packed % U32)
      if candidate_count % 12 == 0 then c:write("  ") end
      c:write(tostring(id), ", ")
      candidate_count = candidate_count + 1
      if candidate_count % 12 == 0 then c:write("\n") end
    end
  end
  if candidate_count % 12 ~= 0 then c:write("\n") end
  c:write("};\n")

  c:write("static const PatternEntry spon_patterns[] = {\n")
  local start = 0
  for _, k in ipairs(pattern_keys) do
    local list = patterns[k]
    local len = math.floor(k / U32)
    local packed = math.floor(k - len * U32)
    c:write(string.format("  {0x%x%08xULL, %d, %d},\n", len, packed, start, #list))
    start = start + #list
  end
  c:write("};\n")
  c:write(string.format("static const uint32_t spon_pattern_count = %d;\n\n", #pattern_keys))

  c:write([[
static const SponBankShard *find_shard(SponStencilId id) {
  uint32_t lo = 0, hi = spon_shard_count;
  while (lo < hi) {
    uint32_t mid = lo + ((hi - lo) >> 1);
    const SponBankShard *s = &spon_shards[mid];
    if (id < s->first) hi = mid;
    else if (id >= s->first + s->count) lo = mid + 1;
    else return s;
  }
  return NULL;
}

static const PatternEntry *find_pattern(uint64_t key) {
  uint32_t lo = 0, hi = spon_pattern_count;
  while (lo < hi) {
    uint32_t mid = lo + ((hi - lo) >> 1);
    uint64_t mk = spon_patterns[mid].pattern_key;
    if (mk == key) return &spon_patterns[mid];
    if (mk < key) lo = mid + 1; else hi = mid;
  }
  return NULL;
}

static uint64_t make_pattern_key(const uint32_t *bc, uint32_t pc, uint32_t len) {
  uint32_t packed = 0;
  for (uint32_t i = 0; i < len; i++) packed |= ((bc[pc + i] & 0xffu) << (i * 8));
  return (((uint64_t)len) << 32) | (uint64_t)packed;
}

uint32_t spon_bank_stencil_count(void) { return spon_stencil_count; }
uint32_t spon_bank_pattern_count(void) { return spon_pattern_count; }

const SponStencilDesc *spon_get_stencil(SponStencilId id) {
  const SponBankShard *s = find_shard(id);
  if (!s) return NULL;
  return &s->stencils[id - s->first];
}

const unsigned char *spon_stencil_data(SponStencilId id) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->size == 0) return NULL;
  return s->data + f->offset;
}

const SponEndpointDesc *spon_stencil_endpoints(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_endpoints == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_endpoints;
  return s->endpoints + f->endpoint_start;
}

const SponLocationDesc *spon_stencil_locations(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_endpoints == 0) { if (out_n) *out_n = 0; return NULL; }
  uint32_t first = 0xffffffffu;
  uint32_t last = 0;
  const SponEndpointDesc *eps = s->endpoints + f->endpoint_start;
  for (uint32_t i = 0; i < f->n_endpoints; i++) {
    if (eps[i].n_locations == 0) continue;
    if (eps[i].location_start < first) first = eps[i].location_start;
    if (eps[i].location_start + eps[i].n_locations > last) last = eps[i].location_start + eps[i].n_locations;
  }
  if (first == 0xffffffffu || last <= first) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = last - first;
  return s->locations + first;
}

const SponDataReloc *spon_stencil_data_relocs(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_data_relocs == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_data_relocs;
  return s->data_relocs + f->data_reloc_start;
}

const SponControlReloc *spon_stencil_control_relocs(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_control_relocs == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_control_relocs;
  return s->control_relocs + f->control_reloc_start;
}

const SponSlotMapEntry *spon_stencil_slotmaps(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_slotmaps == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_slotmaps;
  return s->slotmaps + f->slotmap_start;
}

const SponProjectionEntry *spon_stencil_projections(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_projections == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_projections;
  return s->projections + f->projection_start;
}

const SponDependencyDesc *spon_stencil_dependencies(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_dependencies == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_dependencies;
  return s->dependencies + f->dependency_start;
}

SponStencilId spon_l0_stencil_for_opcode(uint32_t opcode) {
  return opcode < 256 ? spon_l0[opcode] : 0;
}

static int actual_slot_lookup(const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots, uint16_t op_idx, uint8_t field_kind, uint8_t *out_slot) {
  for (uint32_t i = 0; i < n_actual_slots; i++) {
    if (actual_slots[i].op_idx == op_idx && actual_slots[i].field_kind == field_kind) { *out_slot = actual_slots[i].logical_slot; return 1; }
  }
  return 0;
}

static int stencil_matches_actual_slots(const SponStencilDesc *f, const SponBankShard *s, uint32_t pc, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots) {
  if (!actual_slots) return 1;
  uint8_t logical_seen[256] = {0};
  uint8_t logical_to_actual[256] = {0};
  uint8_t actual_seen[256] = {0};
  uint8_t actual_to_logical[256] = {0};
  const SponSlotMapEntry *sms = s->slotmaps + f->slotmap_start;
  for (uint32_t i = 0; i < f->n_slotmaps; i++) {
    uint8_t actual = 0;
    uint8_t logical = sms[i].logical_slot;
    if (!actual_slot_lookup(actual_slots, n_actual_slots, (uint16_t)(pc + sms[i].op_idx), sms[i].field_kind, &actual)) return 0;
    if (actual >= 8) return 0;
    if (logical_seen[logical] && logical_to_actual[logical] != actual) return 0;
    logical_seen[logical] = 1;
    logical_to_actual[logical] = actual;
    if (actual_seen[actual] && actual_to_logical[actual] != logical) return 0;
    actual_seen[actual] = 1;
    actual_to_logical[actual] = logical;
  }
  return 1;
}

static SponFactSig remap_stencil_sig(const SponStencilDesc *f, const SponBankShard *s, SponFactSig sig, uint32_t pc, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots) {
  if (!f || !actual_slots) return sig;
  uint8_t map[8] = {0};
  uint8_t seen[8] = {0};
  const SponSlotMapEntry *sms = s->slotmaps + f->slotmap_start;
  for (uint32_t i = 0; i < f->n_slotmaps; i++) {
    uint8_t logical = sms[i].logical_slot;
    uint8_t actual = 0;
    if (logical >= 8) continue;
    if (!actual_slot_lookup(actual_slots, n_actual_slots, (uint16_t)(pc + sms[i].op_idx), sms[i].field_kind, &actual)) continue;
    if (actual < 8) { seen[logical] = 1; map[logical] = actual; }
  }
  SponFactSig out = sig & 0x7f00000000000000ULL;
  static const uint8_t bases[] = {0,8,16,24,32,40,48};
  for (uint32_t bi = 0; bi < sizeof(bases); bi++) {
    uint8_t base = bases[bi];
    for (uint8_t slot = 0; slot < 8; slot++) {
      SponFactSig bit = ((SponFactSig)1) << (base + slot);
      if ((sig & bit) == 0) continue;
      uint8_t dst = seen[slot] ? map[slot] : slot;
      if (dst < 8) out |= ((SponFactSig)1) << (base + dst);
    }
  }
  return out;
}

static SponFactSig apply_transfer(SponFactSig facts, const SponStencilDesc *f, const SponBankShard *s, uint32_t pc, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots) {
  if (!f) return facts;
  SponFactSig killed = remap_stencil_sig(f, s, f->killed_sig, pc, actual_slots, n_actual_slots);
  SponFactSig produced = remap_stencil_sig(f, s, f->produced_sig, pc, actual_slots, n_actual_slots);
  SponFactSig checked = remap_stencil_sig(f, s, f->checked_sig, pc, actual_slots, n_actual_slots);
  facts &= ~killed;
  facts |= produced;
  facts |= checked;
  return facts;
}

static const SponStencilChoice *select_flow_impl(const uint32_t *bc, uint32_t start, uint32_t end, SponFactSig entry_sig, SponFactSig observed_sig, uint16_t required_stencil_flags, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots, uint32_t *out_n, SponSelectStats *stats) {
  static __thread SponStencilChoice choices[4096];
  uint32_t n = 0;
  uint32_t pc = start;
  uint64_t probes = 0, checks = 0;
  SponFactSig facts = entry_sig;
  if (stats) {
    stats->pattern_probes = 0;
    stats->candidate_checks = 0;
    stats->choices = 0;
    stats->status = SPON_SELECT_OK;
    stats->covered_end = start;
    stats->first_uncovered_pc = end;
    stats->no_candidate_opcode = 0;
  }
  while (pc < end && n < 4096) {
    SponStencilId chosen = 0;
    const SponStencilDesc *chosen_f = NULL;
    const SponBankShard *chosen_s = NULL;
    uint32_t chosen_len = 1;
    SponFactSig available_sig = observed_sig | facts;
    for (int len = 4; len >= 1; len--) {
      if (pc + (uint32_t)len > end) continue;
      probes++;
      const PatternEntry *pe = find_pattern(make_pattern_key(bc, pc, (uint32_t)len));
      if (!pe) continue;
      for (uint32_t i = 0; i < pe->count; i++) {
        checks++;
        SponStencilId fid = spon_candidates[pe->start + i];
        const SponBankShard *s = find_shard(fid);
        const SponStencilDesc *f = spon_get_stencil(fid);
        if (!s || !f) continue;
        if ((f->flags & required_stencil_flags) != required_stencil_flags) continue;
        if (!stencil_matches_actual_slots(f, s, pc, actual_slots, n_actual_slots)) continue;
        SponFactSig fsel = remap_stencil_sig(f, s, f->selector_sig, pc, actual_slots, n_actual_slots);
        SponFactSig freq = remap_stencil_sig(f, s, f->required_sig, pc, actual_slots, n_actual_slots);
        if (((fsel & ~available_sig) == 0) && ((freq & ~facts) == 0)) { chosen = fid; chosen_len = (uint32_t)len; chosen_f = f; chosen_s = s; break; }
      }
      if (chosen) break;
    }
    if (!chosen) {
      if (stats) {
        stats->status = SPON_SELECT_NO_CANDIDATE;
        stats->covered_end = pc;
        stats->first_uncovered_pc = pc;
        stats->no_candidate_opcode = bc ? (bc[pc] & 0xffu) : 0;
      }
      break;
    }
    choices[n].stencil_id = chosen;
    choices[n].pc_start = pc;
    choices[n].pc_end = pc + chosen_len;
    n++;
    facts = apply_transfer(facts, chosen_f, chosen_s, pc, actual_slots, n_actual_slots);
    pc += chosen_len;
  }
  if (out_n) *out_n = n;
  if (stats) {
    stats->pattern_probes = probes;
    stats->candidate_checks = checks;
    stats->choices = n;
    stats->covered_end = pc;
    if (stats->status == SPON_SELECT_OK && pc < end) {
      stats->status = SPON_SELECT_CAPACITY;
      stats->first_uncovered_pc = pc;
      stats->no_candidate_opcode = bc ? (bc[pc] & 0xffu) : 0;
    }
  }
  return choices;
}

const SponStencilChoice *spon_select_greedy_stats(const uint32_t *bc, uint32_t start, uint32_t end, SponFactSig observed_sig, uint32_t *out_n, SponSelectStats *stats) {
  return select_flow_impl(bc, start, end, 0, observed_sig, 0, NULL, 0, out_n, stats);
}
const SponStencilChoice *spon_select_greedy(const uint32_t *bc, uint32_t start, uint32_t end, SponFactSig observed_sig, uint32_t *out_n) {
  return select_flow_impl(bc, start, end, 0, observed_sig, 0, NULL, 0, out_n, NULL);
}
const SponStencilChoice *spon_select_flow_stats(const uint32_t *bc, uint32_t start, uint32_t end, SponFactSig entry_sig, SponFactSig observed_sig, uint32_t *out_n, SponSelectStats *stats) {
  return select_flow_impl(bc, start, end, entry_sig, observed_sig, 0, NULL, 0, out_n, stats);
}
const SponStencilChoice *spon_select_flow(const uint32_t *bc, uint32_t start, uint32_t end, SponFactSig entry_sig, SponFactSig observed_sig, uint32_t *out_n) {
  return select_flow_impl(bc, start, end, entry_sig, observed_sig, 0, NULL, 0, out_n, NULL);
}
const SponStencilChoice *spon_select_flow_flags_stats(const uint32_t *bc, uint32_t start, uint32_t end, SponFactSig entry_sig, SponFactSig observed_sig, uint16_t required_stencil_flags, uint32_t *out_n, SponSelectStats *stats) {
  return select_flow_impl(bc, start, end, entry_sig, observed_sig, required_stencil_flags, NULL, 0, out_n, stats);
}
const SponStencilChoice *spon_select_flow_flags(const uint32_t *bc, uint32_t start, uint32_t end, SponFactSig entry_sig, SponFactSig observed_sig, uint16_t required_stencil_flags, uint32_t *out_n) {
  return select_flow_impl(bc, start, end, entry_sig, observed_sig, required_stencil_flags, NULL, 0, out_n, NULL);
}
const SponStencilChoice *spon_select_flow_flags_slots_stats(const uint32_t *bc, uint32_t start, uint32_t end, SponFactSig entry_sig, SponFactSig observed_sig, uint16_t required_stencil_flags, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots, uint32_t *out_n, SponSelectStats *stats) {
  return select_flow_impl(bc, start, end, entry_sig, observed_sig, required_stencil_flags, actual_slots, n_actual_slots, out_n, stats);
}
const SponStencilChoice *spon_select_flow_flags_slots(const uint32_t *bc, uint32_t start, uint32_t end, SponFactSig entry_sig, SponFactSig observed_sig, uint16_t required_stencil_flags, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots, uint32_t *out_n) {
  return select_flow_impl(bc, start, end, entry_sig, observed_sig, required_stencil_flags, actual_slots, n_actual_slots, out_n, NULL);
}
]])
  c:close()

  return { patterns = #pattern_keys, candidates = candidate_count, c_file = Util.basename(c_path) }
end

local function emit_sqlite_shard(db, out_dir, shard_index, first_id, last_id, patterns, l0)
  local prefix = string.format("bank_chunk_%d", shard_index)
  local inc = {}
  inc.stencils = select(1, open_inc(out_dir, prefix, "stencils"))
  inc.data_bytes = select(1, open_inc(out_dir, prefix, "data"))
  inc.endpoints = select(1, open_inc(out_dir, prefix, "endpoints"))
  inc.locations = select(1, open_inc(out_dir, prefix, "locations"))
  inc.data_relocs = select(1, open_inc(out_dir, prefix, "data_relocs"))
  inc.control_relocs = select(1, open_inc(out_dir, prefix, "control_relocs"))
  inc.slotmaps = select(1, open_inc(out_dir, prefix, "slotmaps"))
  inc.projections = select(1, open_inc(out_dir, prefix, "projections"))
  inc.dependencies = select(1, open_inc(out_dir, prefix, "dependencies"))

  local counts = {
    stencils = 0,
    bytes = 1,
    endpoints = 0,
    locations = 0,
    data_relocs = 0,
    control_relocs = 0,
    slotmaps = 0,
    projections = 0,
    dependencies = 0,
  }

  local sql = string.format("SELECT bank_id AS id, stencil_json FROM unique_forms WHERE lower_ok = 1 AND stencil_json IS NOT NULL AND bank_id >= %d AND bank_id <= %d ORDER BY bank_id", first_id, last_id)
  for row in db:nrows(sql) do
    local stencil_id = tonumber(row.id)
    local stencil = assert(cjson.decode(row.stencil_json))
    local abi = assert(stencil.abi, "stencil row missing abi")
    local af = assert(abi.stencil, "stencil row missing abi.stencil")
    local len = u(af.len ~= nil and af.len or stencil.len)
    local pattern_lit = as_c_u64_literal(af.pattern_key)
    local selector_sig = as_c_u64_literal(af.selector_sig)
    local required_sig = as_c_u64_literal(af.required_sig)
    local checked_sig = as_c_u64_literal(af.checked_sig)
    local produced_sig = as_c_u64_literal(af.produced_sig)
    local killed_sig = as_c_u64_literal(af.killed_sig)

    local code_bytes = hex_to_bytes(stencil.code_hex or abi.code_hex)
    local byte_start = (#code_bytes > 0) and counts.bytes or 0
    local byte_size = #code_bytes
    local endpoints = abi.endpoints or {}
    local locations = abi.locations or {}
    local data_relocs = abi.data_relocs or {}
    local control_relocs = abi.control_relocs or {}
    local slotmaps = abi.slotmaps or {}
    local projections = abi.projections or {}
    local dependencies = abi.dependencies or {}

    local endpoint_start = (#endpoints > 0) and (counts.endpoints + 1) or 0
    local location_start = (#locations > 0) and (counts.locations + 1) or 0
    local data_reloc_start = (#data_relocs > 0) and (counts.data_relocs + 1) or 0
    local control_reloc_start = (#control_relocs > 0) and (counts.control_relocs + 1) or 0
    local slotmap_start = (#slotmaps > 0) and (counts.slotmaps + 1) or 0
    local projection_start = (#projections > 0) and (counts.projections + 1) or 0
    local dependency_start = (#dependencies > 0) and (counts.dependencies + 1) or 0

    inc.stencils:write(string.format(
      "  {%d, %d, %d, %d, %d, %d, %d, %d, %d, %d, %d, %d, %d, %d, %d, %d, %d, %d, 0, %s, %s, %s, %s, %s, %s}, /* %s */\n",
      stencil_id, byte_start, byte_size, endpoint_start, data_reloc_start, control_reloc_start, slotmap_start, projection_start,
      dependency_start, len, #endpoints, #data_relocs, #control_relocs, #slotmaps, #projections, #dependencies,
      u(af.flags or 1), u(af.physical_abi or 1), pattern_lit, selector_sig, required_sig, checked_sig, produced_sig,
      killed_sig, tostring(stencil.name or "stencil")))

    for i, b in ipairs(code_bytes) do
      if counts.bytes % 16 == 0 then inc.data_bytes:write("  ") end
      inc.data_bytes:write(string.format("0x%02x, ", b))
      counts.bytes = counts.bytes + 1
      if counts.bytes % 16 == 0 then inc.data_bytes:write("\n") end
    end
    if #code_bytes > 0 and counts.bytes % 16 ~= 0 then inc.data_bytes:write("\n") end

    for _, loc in ipairs(locations) do
      inc.locations:write(string.format("  {%d, %d, %d, 0, %d},\n", u(loc.kind), u(loc.value_type), u(loc.reg), u(loc.index)))
      counts.locations = counts.locations + 1
    end
    for _, ep in ipairs(endpoints) do
      local ep_loc_start = u(ep.location_start)
      if ep_loc_start > 0 then ep_loc_start = location_start + ep_loc_start - 1 end
      local ep_proj_start = u(ep.projection_start)
      if ep_proj_start > 0 then ep_proj_start = projection_start + ep_proj_start - 1 end
      inc.endpoints:write(string.format("  {%d, %d, %d, %d, %d, %d, %d},\n", u(ep.kind), u(ep.flags), ep_loc_start, u(ep.n_locations), 0, ep_proj_start, u(ep.n_projections)))
      counts.endpoints = counts.endpoints + 1
    end
    for _, r in ipairs(data_relocs) do
      inc.data_relocs:write(string.format("  {%d, %d, %d, %d, %d, %d},\n", u(r.code_offset), u(r.reloc_kind), u(r.role_kind), u(r.op_idx), u(r.role_arg), u(r.addend)))
      counts.data_relocs = counts.data_relocs + 1
    end
    for _, r in ipairs(control_relocs) do
      inc.control_relocs:write(string.format("  {%d, %d, %d, %d, %d},\n", u(r.code_offset), u(r.reloc_kind), u(r.edge_kind), u(r.endpoint_index), u(r.target_delta)))
      counts.control_relocs = counts.control_relocs + 1
    end
    for _, sm in ipairs(slotmaps) do
      inc.slotmaps:write(string.format("  {%d, %d, %d},\n", u(sm.op_idx), u(sm.logical_slot), u(sm.field_kind)))
      counts.slotmaps = counts.slotmaps + 1
    end
    for _, p in ipairs(projections) do
      inc.projections:write(string.format("  {%d, %d, %d, %d, %d},\n", u(p.kind), u(p.value_type), u(p.logical_slot), u(p.value_index), u(p.pc)))
      counts.projections = counts.projections + 1
    end
    for _, d in ipairs(dependencies) do
      inc.dependencies:write(string.format("  {%s},\n", c_string(d.name or d[1] or "")))
      counts.dependencies = counts.dependencies + 1
    end

    counts.stencils = counts.stencils + 1
    if counts.stencils % 10000 == 0 then io.stderr:write(string.format("[bank] shard %d stencils=%d\n", shard_index, counts.stencils)) end
  end
  for _, f in pairs(inc) do f:close() end

  local c_path = string.format("%s/%s.c", out_dir, prefix)
  local c = assert(io.open(c_path, "wb"))
  c:write("/* Generated by src/build_bank.lua. Native stencil bank shard. */\n")
  c:write('#include "sponbank.h"\n#include <stddef.h>\n#include <stdint.h>\n\n')
  write_array_header(c, "SponStencilDesc", string.format("spon_chunk_%d_stencils", shard_index), nil)
  write_include(c, string.format("%s_%s.inc", prefix, "stencils")); write_array_footer(c)
  write_array_header(c, "unsigned char", string.format("spon_chunk_%d_data", shard_index), "0,")
  write_include(c, string.format("%s_%s.inc", prefix, "data")); write_array_footer(c)
  write_array_header(c, "SponEndpointDesc", string.format("spon_chunk_%d_endpoints", shard_index), "{0, 0, 0, 0, 0, 0, 0},")
  write_include(c, string.format("%s_%s.inc", prefix, "endpoints")); write_array_footer(c)
  write_array_header(c, "SponLocationDesc", string.format("spon_chunk_%d_locations", shard_index), "{0, 0, 0, 0, 0},")
  write_include(c, string.format("%s_%s.inc", prefix, "locations")); write_array_footer(c)
  write_array_header(c, "SponDataReloc", string.format("spon_chunk_%d_data_relocs", shard_index), "{0, 0, 0, 0, 0, 0},")
  write_include(c, string.format("%s_%s.inc", prefix, "data_relocs")); write_array_footer(c)
  write_array_header(c, "SponControlReloc", string.format("spon_chunk_%d_control_relocs", shard_index), "{0, 0, 0, 0, 0},")
  write_include(c, string.format("%s_%s.inc", prefix, "control_relocs")); write_array_footer(c)
  write_array_header(c, "SponSlotMapEntry", string.format("spon_chunk_%d_slotmaps", shard_index), "{0, 0, 0},")
  write_include(c, string.format("%s_%s.inc", prefix, "slotmaps")); write_array_footer(c)
  write_array_header(c, "SponProjectionEntry", string.format("spon_chunk_%d_projections", shard_index), "{0, 0, 0, 0, 0},")
  write_include(c, string.format("%s_%s.inc", prefix, "projections")); write_array_footer(c)
  write_array_header(c, "SponDependencyDesc", string.format("spon_chunk_%d_dependencies", shard_index), "{NULL},")
  write_include(c, string.format("%s_%s.inc", prefix, "dependencies")); write_array_footer(c)
  c:close()

  return {
    chunk = shard_index,
    first = first_id,
    count = counts.stencils,
    bytes = counts.bytes,
    endpoints = counts.endpoints,
    locations = counts.locations,
    data_relocs = counts.data_relocs,
    control_relocs = counts.control_relocs,
    slotmaps = counts.slotmaps,
    projections = counts.projections,
    dependencies = counts.dependencies,
    c_file = Util.basename(c_path),
  }
end

local function add_pattern_candidate(patterns, l0, ops, stencil_id, selector_sig, flags)
  local pattern_num = selector_key_num(ops)
  local score = sig_pop(selector_sig)
  local list = patterns[pattern_num]
  if not list then list = {}; patterns[pattern_num] = list end
  list[#list + 1] = score * U32 + stencil_id

  if #(ops or {}) == 1 and has_flag(flags, 2) and has_flag(flags, 8) then
    local opcode = OPCODE[op_name(ops[1])] or nil
    if opcode and opcode >= 0 and opcode < 256 then
      if selector_sig == "0x0000000000000000ULL" or not l0[opcode] then l0[opcode] = stencil_id end
    end
  end
end

local function load_pattern_aliases(db, patterns, l0)
  local n = 0
  local sql = [[SELECT u.bank_id AS id, u.selector_sig AS selector_sig, u.stencil_json AS stencil_json, p.ops_json AS ops_json
    FROM unique_forms u JOIN form_patterns p ON p.dedupe_key = u.dedupe_key
    WHERE u.lower_ok = 1 AND u.stencil_json IS NOT NULL AND u.bank_id IS NOT NULL
    ORDER BY p.ops_key, u.id]]
  for row in db:nrows(sql) do
    local stencil = assert(cjson.decode(row.stencil_json))
    local flags = stencil.abi and stencil.abi.stencil and stencil.abi.stencil.flags or stencil.flags or 0
    add_pattern_candidate(patterns, l0, assert(cjson.decode(row.ops_json)), tonumber(row.id), as_c_u64_literal(row.selector_sig), flags)
    n = n + 1
    if n % 100000 == 0 then io.stderr:write(string.format("[bank] loaded %d pattern aliases\n", n)) end
  end
  return n
end

function M.build(bank_src, out_dir)
  bank_src = bank_src or "build/stencil_bank"
  out_dir = out_dir or "build/sponbank"
  mkdir_p(out_dir)

  local db_path = bank_src
  if not tostring(db_path):match("%.sqlite$") then db_path = bank_src .. "/stencil_bank.sqlite" end
  assert(Util.path_exists(db_path), "missing SQLite stencil bank: " .. db_path)
  local db = assert(sqlite3.open(db_path))

  local total_stencils, max_id = 0, 0
  for row in db:nrows("SELECT COUNT(*) AS n, COALESCE(MAX(bank_id), 0) AS max_id FROM unique_forms WHERE lower_ok = 1 AND stencil_json IS NOT NULL AND bank_id IS NOT NULL") do
    total_stencils = tonumber(row.n) or 0
    max_id = tonumber(row.max_id) or 0
  end
  assert(total_stencils > 0, "stencil_bank.sqlite has no lowered stencil rows")

  local rows_per_shard = tonumber(os.getenv("BANK_ROWS_PER_SHARD") or "50000") or 50000
  local patterns = {}
  local l0 = {}
  local shards = {}
  local t0 = os.time()
  local shard_index = 1
  local first_id = 1
  while first_id <= max_id do
    local last_id = math.min(max_id, first_id + rows_per_shard - 1)
    io.stderr:write(string.format("[bank] generating shard %d ids=%d..%d\n", shard_index, first_id, last_id))
    local shard = emit_sqlite_shard(db, out_dir, shard_index, first_id, last_id, patterns, l0)
    if shard.count > 0 then shards[#shards + 1] = shard end
    first_id = last_id + 1
    shard_index = shard_index + 1
  end
  table.sort(shards, function(a, b) return a.first < b.first end)

  io.stderr:write("[bank] loading pattern aliases\n")
  local pattern_aliases = load_pattern_aliases(db, patterns, l0)
  local l0_exact_covered, l0_missing, seen_opcode = 0, {}, {}
  for _, opcode in pairs(OPCODE) do
    if type(opcode) == "number" and opcode >= 0 and opcode <= 84 and not seen_opcode[opcode] then
      seen_opcode[opcode] = true
      if l0[opcode] then l0_exact_covered = l0_exact_covered + 1 else l0_missing[#l0_missing + 1] = opcode end
    end
  end
  table.sort(l0_missing)
  if os.getenv("SPON_STRICT_SEMANTIC_L0") == "1" and #l0_missing > 0 then
    error("strict semantic L0 coverage missing opcodes: " .. table.concat(l0_missing, ","))
  end

  local semantic_inline_stencils, semantic_boundary_stencils = 0, 0
  for row in db:nrows("SELECT stencil_json FROM unique_forms WHERE lower_ok = 1 AND stencil_json IS NOT NULL AND bank_id IS NOT NULL") do
    local stencil = assert(cjson.decode(row.stencil_json))
    local mode = stencil.semantic_mode or ((stencil.abi and stencil.abi.stencil and has_flag(stencil.abi.stencil.flags, 16)) and "boundary" or "inline")
    if mode == "boundary" then semantic_boundary_stencils = semantic_boundary_stencils + 1
    else semantic_inline_stencils = semantic_inline_stencils + 1 end
  end
  db:close()

  io.stderr:write("[bank] generating index/selector\n")
  local index = emit_index(out_dir, shards, patterns, l0, total_stencils)

  local summary = {
    kind = "sponjit.c_stencil_bank_build.v1",
    source = db_path,
    output = out_dir,
    stencils = total_stencils,
    max_id = max_id,
    rows_per_shard = rows_per_shard,
    chunks = #shards,
    patterns = index.patterns,
    candidates = index.candidates,
    pattern_aliases = pattern_aliases,
    l0_exact_covered = l0_exact_covered,
    l0_missing = l0_missing,
    semantic_inline_stencils = semantic_inline_stencils,
    semantic_boundary_stencils = semantic_boundary_stencils,
    seconds = os.time() - t0,
    shards = shards,
    index = index,
  }
  assert(Util.write_json(out_dir .. "/sponbank_build_manifest.json", summary))
  io.stderr:write(string.format("[bank] stencils=%d patterns=%d candidates=%d shards=%d done in %ds\n", summary.stencils, summary.patterns, summary.candidates, summary.chunks, summary.seconds))
  return summary
end

if arg and arg[0] and tostring(arg[0]):match("build_bank%.lua$") then
  M.build(arg[1] or "build/stencil_bank", arg[2] or "build/sponbank")
end

return M

#!/usr/bin/env luajit

package.path = "./?.lua;./?/init.lua;./experiments/lua_interpreter_vm/spongejit/?.lua;" .. package.path

local ffi = require("ffi")
local bit = require("bit")
local Constants = require("experiments.lua_interpreter_vm.src.constants")

ffi.cdef[[
typedef unsigned int uint32_t;
typedef unsigned short uint16_t;
typedef unsigned long long uint64_t;
typedef uint64_t SponFactSig;
typedef uint32_t SponStencilId;

typedef struct {
  uint32_t code_offset;
  uint16_t reloc_kind;
  uint16_t edge_kind;
  uint16_t endpoint_index;
  int32_t target_delta;
} SponControlReloc;

typedef struct {
  SponStencilId stencil_id;
  uint32_t offset;
  uint32_t size;
  uint32_t endpoint_start;
  uint32_t data_reloc_start;
  uint32_t control_reloc_start;
  uint32_t slotmap_start;
  uint32_t projection_start;
  uint32_t dependency_start;
  uint16_t len;
  uint16_t n_endpoints;
  uint16_t n_data_relocs;
  uint16_t n_control_relocs;
  uint16_t n_slotmaps;
  uint16_t n_projections;
  uint16_t n_dependencies;
  uint16_t flags;
  uint16_t physical_abi;
  uint16_t reserved;
  uint64_t pattern_key;
  SponFactSig selector_sig;
  SponFactSig required_sig;
  SponFactSig checked_sig;
  SponFactSig produced_sig;
  SponFactSig killed_sig;
} SponStencilDesc;

uint32_t spon_bank_stencil_count(void);
const SponStencilDesc *spon_get_stencil(SponStencilId id);
const unsigned char *spon_stencil_data(SponStencilId id);
const SponControlReloc *spon_stencil_control_relocs(SponStencilId id, uint32_t *out_n);
SponStencilId spon_l0_stencil_for_opcode(uint32_t opcode);
]]

local bank_path = "experiments/lua_interpreter_vm/spongejit/build/sponbank/libsponbank.so"
local f = io.open(bank_path, "rb")
assert(f, "missing generated L1 bank: " .. bank_path)
f:close()

local bank = ffi.load(bank_path)
assert(bank.spon_bank_stencil_count() > 0, "empty generated bank")

local op_name = {}
for name, opcode in pairs(Constants.Op) do
  if type(opcode) == "number" and not op_name[opcode] then op_name[opcode] = name end
end

local strict = os.getenv("SPON_STRICT_SEMANTIC_L0") == "1"
local missing, bad = {}, {}
for opcode = 0, 84 do
  local id = tonumber(bank.spon_l0_stencil_for_opcode(opcode))
  local name = op_name[opcode] or ("OP_" .. tostring(opcode))
  if id == 0 then
    missing[#missing + 1] = string.format("%d:%s", opcode, name)
  else
    local d = bank.spon_get_stencil(id)
    local data = bank.spon_stencil_data(id)
    if d == nil then
      bad[#bad + 1] = string.format("%d:%s id=%d missing descriptor", opcode, name, id)
    elseif bit.band(tonumber(d.flags), 10) ~= 10 then
      bad[#bad + 1] = string.format("%d:%s id=%d not exact native flags=%d", opcode, name, id, tonumber(d.flags))
    elseif tonumber(d.size) <= 0 or data == nil then
      bad[#bad + 1] = string.format("%d:%s id=%d no native bytes", opcode, name, id)
    else
      local nrel = ffi.new("uint32_t[1]")
      local rels = bank.spon_stencil_control_relocs(id, nrel)
      for i = 0, tonumber(nrel[0]) - 1 do
        local edge = tonumber(rels[i].edge_kind)
        if edge < 1 or edge > 4 then
          bad[#bad + 1] = string.format("%d:%s id=%d unknown control edge=%d", opcode, name, id, edge)
        end
      end
    end
  end
end

assert(#bad == 0, "bad semantic L0 bank entries: " .. table.concat(bad, "; "))
if strict then
  assert(#missing == 0, "strict semantic L0 coverage missing opcodes: " .. table.concat(missing, ", "))
else
  io.stderr:write(string.format("[semantic-l0] exact native L0 entries=%d missing=%d\n", 85 - #missing, #missing))
end

print("ok - SpongeJIT generated bank reports truthful semantic L0 coverage")

#!/usr/bin/env luajit

package.path = "./experiments/lua_interpreter_vm/spongejit/?.lua;" .. package.path

local ffi = require("ffi")
local Facts = require("src.facts")
local SSA = require("src.ssa")
local StencilLower = require("src.stencil_lower")

ffi.cdef[[
typedef unsigned long size_t;
typedef struct SponTValueABI {
  unsigned long long value_;
  unsigned char tt_;
} SponTValueABI;
typedef struct SponExecCtx {
  void *stack;
  SponTValueABI *k;
  SponTValueABI scratch[256];
  uint32_t exit_kind;
  uint32_t exit_pc;
  uint32_t exit_op_idx;
  uint32_t exit_hole;
} SponExecCtx;
typedef struct SponTestTable {
  uint32_t shape_id;
  uint32_t pad0;
  void *metatable;
  SponTValueABI field0;
  SponTValueABI field1;
} SponTestTable;
void *mmap(void *addr, size_t length, int prot, int flags, int fd, long offset);
int munmap(void *addr, size_t length);
void *memcpy(void *dest, const void *src, size_t n);
]]

local function assert_eq(a, b, msg) if a ~= b then error((msg or "assert_eq failed") .. ": " .. tostring(a) .. " ~= " .. tostring(b), 2) end end
local function assert_true(x, msg) if not x then error(msg or "assert_true failed", 2) end end

local function hex_to_buf(hex)
  local n = #hex / 2
  local buf = ffi.new("uint8_t[?]", n)
  local i = 0
  for pair in hex:gmatch("%x%x") do buf[i] = tonumber(pair, 16); i = i + 1 end
  return buf, n
end

local function write_i64(buf, off, v)
  local n = tonumber(v)
  local neg = n < 0
  if neg then n = -n end
  local bytes = {}
  for i = 0, 7 do
    bytes[i] = n % 256
    n = math.floor(n / 256)
  end
  if neg then
    local carry = 1
    for i = 0, 7 do
      local x = 255 - bytes[i] + carry
      if x >= 256 then x = x - 256; carry = 1 else carry = 0 end
      bytes[i] = x
    end
  end
  for i = 0, 7 do buf[off + i] = bytes[i] end
end

local function read_i64(stack, slot)
  return tonumber(ffi.cast("int64_t *", stack)[(slot or 0) * 2])
end

local function read_f64(stack, slot)
  return tonumber(ffi.cast("double *", stack)[(slot or 0) * 2])
end

local function f64_bytes_from_int(value)
  local n = tonumber(value) or 0
  if n == 0 then return {0, 0, 0, 0, 0, 0, 0, 0} end
  local sign = 0
  if n < 0 then sign = 0x80000000; n = -n end
  local exp = math.floor(math.log(n) / math.log(2))
  local pow = 2 ^ exp
  local mant = math.floor((n / pow - 1) * 2 ^ 52 + 0.5)
  local lo = mant % 4294967296
  local hi = sign + (exp + 1023) * 1048576 + math.floor(mant / 4294967296)
  return {
    lo % 256, math.floor(lo / 256) % 256, math.floor(lo / 65536) % 256, math.floor(lo / 16777216) % 256,
    hi % 256, math.floor(hi / 256) % 256, math.floor(hi / 65536) % 256, math.floor(hi / 16777216) % 256,
  }
end

local function write_f64_from_int(buf, off, v)
  local b = f64_bytes_from_int(v)
  for i = 0, 7 do buf[off + i] = b[i + 1] end
end

local function patch_immediates(buf, f, op)
  for _, dr in ipairs(f.data_relocs or {}) do
    if dr.reloc_kind == "abs64" and dr.role_kind == "imm" then
      local v = op.sbx or op.sBx or op.c or op.b or 0
      if op.op == "LOADF" then write_f64_from_int(buf, dr.code_offset, v) else write_i64(buf, dr.code_offset, v) end
    end
  end
end

local function patch_const_i64(buf, f, value)
  for _, dr in ipairs(f.data_relocs or {}) do
    if dr.reloc_kind == "abs64" and dr.role_kind == "const" then write_i64(buf, dr.code_offset, value) end
  end
end

local function patch_payloads(buf, f, payload)
  payload = payload or {}
  for _, dr in ipairs(f.data_relocs or {}) do
    local v = payload[dr.role_kind]
    if (dr.role_kind == "slot" or dr.role_kind == "slot_store") and payload.slots then
      local actual = payload.slots[tonumber(dr.role_arg) or 0]
      if actual ~= nil then v = tonumber(actual) * 16 end
    end
    if v ~= nil then
      v = tonumber(v) + (tonumber(dr.addend) or 0)
      if dr.reloc_kind == "abs8" then buf[dr.code_offset] = v % 256
      elseif dr.reloc_kind == "abs32" or dr.reloc_kind == "abs32s" then
        local n = v
        if n < 0 then n = n + 4294967296 end
        buf[dr.code_offset] = n % 256
        buf[dr.code_offset + 1] = math.floor(n / 256) % 256
        buf[dr.code_offset + 2] = math.floor(n / 65536) % 256
        buf[dr.code_offset + 3] = math.floor(n / 16777216) % 256
      elseif dr.reloc_kind == "abs64" then write_i64(buf, dr.code_offset, v)
      end
    end
  end
end

local function ptr_u64(p)
  return ffi.cast("uint64_t", ffi.cast("uintptr_t", p))
end

local function executable_copy(buf, n)
  local PROT_READ, PROT_WRITE, PROT_EXEC = 1, 2, 4
  local MAP_PRIVATE, MAP_ANON = 2, 0x20
  local mem = ffi.C.mmap(nil, n, PROT_READ + PROT_WRITE + PROT_EXEC, MAP_PRIVATE + MAP_ANON, -1, 0)
  assert_true(mem ~= ffi.cast("void *", -1), "mmap failed")
  ffi.C.memcpy(mem, buf, n)
  return mem
end

local function lower_native(ops, facts)
  local r = SSA.compile(ops, facts or {})
  assert_true(r.ok, table.concat(r.errors or {}, "\n"))
  local fr = StencilLower.generate(r, { facts = facts or {} })
  assert_true(fr.ok, table.concat(fr.errors or {}, "\n"))
  assert_true(fr.stencil.executable == true and (fr.stencil.code_size or 0) > 0, "native stencil expected")
  return fr.stencil
end

local function run_native(f, patch, setup, check)
  local buf, n = hex_to_buf(f.code_hex)
  if patch then patch(buf, f) end
  local mem = executable_copy(buf, n)
  local fn = ffi.cast("void (*)(SponExecCtx *)", mem)
  local stack = ffi.new("SponTValueABI[8]")
  local k = ffi.new("SponTValueABI[4]")
  local ctx = ffi.new("SponExecCtx")
  ctx.stack = stack
  ctx.k = k
  if setup then setup(ctx, stack, k) end
  fn(ctx)
  if check then check(ctx, stack, k) end
  ffi.C.munmap(mem, n)
end

assert_eq(ffi.sizeof("SponTValueABI"), 16, "TValue ABI size")
assert_eq(ffi.offsetof("SponExecCtx", "exit_kind"), 16 + 256 * 16, "ctx exit offset")

local facts = { Facts.fact("type", Facts.slot("R1"), "is_i64", true) }
local f = lower_native({ { op = "ADDI", a = 1, b = 1, c = 7 } }, facts)
assert_true(f.executable == true, "stencil must be executable")
assert_true((f.code_size or 0) > 0 and type(f.code_hex) == "string", "native code bytes missing")
assert_eq(f.abi.stencil.flags, 10, "native exact flag")

local buf, n = hex_to_buf(f.code_hex)
local saw_abs64, saw_pc32, saw_slot_addend8 = false, false, false
for _, dr in ipairs(f.data_relocs or {}) do
  assert_true(dr.code_offset_kind ~= "abstract_zero", "data reloc must be real")
  if dr.reloc_kind == "abs64" and dr.role_kind == "imm" then write_i64(buf, dr.code_offset, 7); saw_abs64 = true end
  if dr.role_kind == "slot" and dr.addend == 8 then saw_slot_addend8 = true end
end
for _, cr in ipairs(f.control_relocs or {}) do
  assert_eq(cr.reloc_kind, "pc32", "control reloc must be rel32")
  saw_pc32 = true
end
assert_true(saw_abs64, "imm64 patch site missing")
assert_true(saw_pc32, "guard control patch site missing")
assert_true(saw_slot_addend8, "slot tag displacement patch site missing")

local mem = executable_copy(buf, n)
local fn = ffi.cast("void (*)(SponExecCtx *)", mem)
local stack = ffi.new("SponTValueABI[8]")
local ctx = ffi.new("SponExecCtx")
ctx.stack = stack

stack[0].value_ = 35
stack[0].tt_ = 3 -- LUA_VNUMINT
ctx.exit_kind = 99
fn(ctx)
assert_eq(tonumber(ctx.exit_kind), 0, "success exit kind")
assert_eq(tonumber(stack[0].value_), 42, "ADDI native result")
assert_eq(tonumber(stack[0].tt_), 3, "ADDI native result tag")

stack[0].value_ = 35
stack[0].tt_ = 0 -- not integer; guard must branch to local guard endpoint stub
ctx.exit_kind = 99
fn(ctx)
assert_eq(tonumber(ctx.exit_kind), 1, "guard exit kind")
assert_eq(tonumber(ctx.exit_pc), 1, "guard exit pc")

ffi.C.munmap(mem, n)

run_native(lower_native({ { op = "LOADTRUE", a = 0 } }), nil,
  function(ctx, stack) stack[0].value_ = 0; stack[0].tt_ = 0; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "LOADTRUE exit"); assert_eq(tonumber(stack[0].tt_), 17, "LOADTRUE tag") end)

run_native(lower_native({ { op = "LOADNIL", a = 0 } }), nil,
  function(ctx, stack) stack[0].value_ = 123; stack[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "LOADNIL exit"); assert_eq(tonumber(stack[0].tt_), 0, "LOADNIL tag") end)

run_native(lower_native({ { op = "MOVE", a = 0, b = 1 } }), nil,
  function(ctx, stack) stack[1].value_ = 12345; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "MOVE exit"); assert_eq(tonumber(stack[0].value_), 12345, "MOVE value"); assert_eq(tonumber(stack[0].tt_), 3, "MOVE tag") end)

run_native(lower_native({ { op = "LOADK", a = 0, b = 0 } }), nil,
  function(ctx, stack, k) k[0].value_ = 55; k[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "LOADK exit"); assert_eq(tonumber(stack[0].value_), 55, "LOADK value"); assert_eq(tonumber(stack[0].tt_), 3, "LOADK tag") end)

local not_stencil = lower_native({ { op = "NOT", a = 0, b = 1 } })
run_native(not_stencil, nil,
  function(ctx, stack) stack[1].value_ = 0; stack[1].tt_ = 0; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "NOT nil exit"); assert_eq(tonumber(stack[0].tt_), 17, "NOT nil true tag") end)
run_native(not_stencil, nil,
  function(ctx, stack) stack[1].value_ = 0; stack[1].tt_ = 1; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "NOT false exit"); assert_eq(tonumber(stack[0].tt_), 17, "NOT false true tag") end)
run_native(not_stencil, nil,
  function(ctx, stack) stack[1].value_ = 0; stack[1].tt_ = 17; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "NOT true exit"); assert_eq(tonumber(stack[0].tt_), 1, "NOT true false tag") end)
run_native(not_stencil, nil,
  function(ctx, stack) stack[1].value_ = 42; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "NOT int exit"); assert_eq(tonumber(stack[0].tt_), 1, "NOT int false tag") end)

local loadf = lower_native({ { op = "LOADF", a = 0, sbx = 42 } })
run_native(loadf,
  function(buf, f) patch_immediates(buf, f, { op = "LOADF", sbx = 42 }) end,
  function(ctx, stack) stack[0].value_ = 0; stack[0].tt_ = 0; ctx.exit_kind = 99 end,
  function(ctx, stack)
    local d = ffi.cast("double *", stack)[0]
    assert_eq(tonumber(ctx.exit_kind), 0, "LOADF exit")
    assert_eq(tonumber(stack[0].tt_), 19, "LOADF tag")
    assert_true(math.abs(d - 42.0) < 1e-12, "LOADF value")
  end)

local shift_facts = {
  Facts.fact("type", Facts.slot("R0"), "is_i64", true),
  Facts.fact("type", Facts.slot("R1"), "is_i64", true),
}
local shl = lower_native({ { op = "SHL", a = 0, b = 0, c = 1 } }, shift_facts)
run_native(shl, nil,
  function(ctx, stack) stack[0].value_ = 3; stack[0].tt_ = 3; stack[1].value_ = 2; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "SHL exit"); assert_eq(tonumber(stack[0].value_), 12, "SHL result") end)
local shr = lower_native({ { op = "SHR", a = 0, b = 0, c = 1 } }, shift_facts)
run_native(shr, nil,
  function(ctx, stack) stack[0].value_ = 16; stack[0].tt_ = 3; stack[1].value_ = 2; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "SHR exit"); assert_eq(tonumber(stack[0].value_), 4, "SHR result") end)
local shli = lower_native({ { op = "SHLI", a = 0, b = 1, c = 3 } }, { Facts.fact("type", Facts.slot("R1"), "is_i64", true) })
run_native(shli,
  function(buf, f) patch_immediates(buf, f, { op = "SHLI", c = 3 }) end,
  function(ctx, stack) stack[1].value_ = 2; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "SHLI exit"); assert_eq(tonumber(stack[0].value_), 12, "SHLI result") end)
local shri = lower_native({ { op = "SHRI", a = 0, b = 0, c = 2 } }, { Facts.fact("type", Facts.slot("R0"), "is_i64", true) })
run_native(shri,
  function(buf, f) patch_immediates(buf, f, { op = "SHRI", c = 2 }) end,
  function(ctx, stack) stack[0].value_ = 16; stack[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "SHRI exit"); assert_eq(tonumber(stack[0].value_), 4, "SHRI result") end)

local div_facts = {
  Facts.fact("type", Facts.slot("R0"), "is_i64", true),
  Facts.fact("type", Facts.slot("R1"), "is_i64", true),
}
local idiv = lower_native({ { op = "IDIV", a = 0, b = 0, c = 1 } }, div_facts)
run_native(idiv, nil,
  function(ctx, stack) stack[0].value_ = ffi.cast("uint64_t", -7); stack[0].tt_ = 3; stack[1].value_ = 3; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "IDIV exit"); assert_eq(read_i64(stack, 0), -3, "IDIV floors negative quotient"); assert_eq(tonumber(stack[0].tt_), 3, "IDIV tag") end)
run_native(idiv, nil,
  function(ctx, stack) stack[0].value_ = 7; stack[0].tt_ = 3; stack[1].value_ = 0; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx) assert_eq(tonumber(ctx.exit_kind), 1, "IDIV zero divisor guard"); assert_eq(tonumber(ctx.exit_pc), 1, "IDIV guard pc") end)
local mod = lower_native({ { op = "MOD", a = 0, b = 0, c = 1 } }, div_facts)
run_native(mod, nil,
  function(ctx, stack) stack[0].value_ = ffi.cast("uint64_t", -7); stack[0].tt_ = 3; stack[1].value_ = 3; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "MOD exit"); assert_eq(read_i64(stack, 0), 2, "MOD follows Lua floor-mod semantics"); assert_eq(tonumber(stack[0].tt_), 3, "MOD tag") end)
local div = lower_native({ { op = "DIV", a = 0, b = 0, c = 1 } }, div_facts)
run_native(div, nil,
  function(ctx, stack) stack[0].value_ = 7; stack[0].tt_ = 3; stack[1].value_ = 2; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "DIV exit"); assert_eq(tonumber(stack[0].tt_), 19, "DIV result is float"); assert_true(math.abs(read_f64(stack, 0) - 3.5) < 1e-12, "DIV value") end)

local divk_facts = {
  Facts.fact("type", Facts.slot("R0"), "is_i64", true),
  Facts.fact("assumed", Facts.value("K1"), "const_i64", true),
}
local idivk = lower_native({ { op = "IDIVK", a = 0, b = 0, c = 1 } }, divk_facts)
run_native(idivk,
  function(buf, f) patch_const_i64(buf, f, 3) end,
  function(ctx, stack) stack[0].value_ = ffi.cast("uint64_t", -7); stack[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "IDIVK exit"); assert_eq(read_i64(stack, 0), -3, "IDIVK floors negative quotient") end)
local modk = lower_native({ { op = "MODK", a = 0, b = 0, c = 1 } }, divk_facts)
run_native(modk,
  function(buf, f) patch_const_i64(buf, f, 3) end,
  function(ctx, stack) stack[0].value_ = ffi.cast("uint64_t", -7); stack[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "MODK exit"); assert_eq(read_i64(stack, 0), 2, "MODK floor mod") end)
local divk = lower_native({ { op = "DIVK", a = 0, b = 0, c = 1 } }, divk_facts)
run_native(divk,
  function(buf, f) patch_const_i64(buf, f, 2) end,
  function(ctx, stack) stack[0].value_ = 7; stack[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "DIVK exit"); assert_eq(tonumber(stack[0].tt_), 19, "DIVK tag"); assert_true(math.abs(read_f64(stack, 0) - 3.5) < 1e-12, "DIVK value") end)

local cmp_boundary = lower_native({ { op = "TEST", a = 0, b = 0, c = 0 } })
run_native(cmp_boundary, nil,
  function(ctx) ctx.exit_kind = 99 end,
  function(ctx) assert_eq(tonumber(ctx.exit_kind), 2, "TEST boundary exit"); assert_eq(tonumber(ctx.exit_pc), 1, "TEST boundary pc") end)

for _, bop in ipairs({
  { op = "LEN", a = 0, b = 1 },
  { op = "CONCAT", a = 0, b = 0, c = 2 },
  { op = "MMBIN", a = 0, b = 1, c = 0 },
  { op = "MMBINI", a = 0, b = 1, c = 0 },
  { op = "MMBINK", a = 0, b = 1, c = 0 },
  { op = "CLOSE", a = 0 },
  { op = "TBC", a = 0 },
  { op = "NEWTABLE", a = 0, b = 0, c = 0 },
  { op = "SETLIST", a = 0, b = 0, c = 0 },
  { op = "CLOSURE", a = 0, bx = 0 },
  { op = "VARARG", a = 0, c = 0 },
  { op = "GETVARG", a = 0, c = 0 },
  { op = "ERRNNIL", a = 0 },
  { op = "VARARGPREP", a = 0 },
  { op = "EXTRAARG", ax = 0 },
}) do
  local bf = lower_native({ bop })
  assert_eq(bf.semantic_mode, "boundary", bop.op .. " semantic boundary")
  run_native(bf, nil,
    function(ctx) ctx.exit_kind = 99 end,
    function(ctx) assert_eq(tonumber(ctx.exit_kind), 2, bop.op .. " boundary exit"); assert_eq(tonumber(ctx.exit_pc), 1, bop.op .. " boundary pc") end)
end

local function field_facts(include_barrier)
  local xs = {
    Facts.fact("type", Facts.slot("R0"), "is_table", true),
    Facts.fact("shape", Facts.slot("R0"), "shape_eq", "shape:test"),
    Facts.fact("metatable", Facts.slot("R0"), "metatable_absent", true),
    Facts.fact("constant", Facts.value("K2"), "key_const", true),
    Facts.fact("shape", Facts.value("K2"), "field_offset", "shape:test"),
  }
  if include_barrier then xs[#xs + 1] = Facts.fact("gc", Facts.global_subject(), "barrier_clean", true) end
  return xs
end

local field_payload = {
  shape_offset = ffi.offsetof("SponTestTable", "shape_id"),
  shape_id = 0x1234abcd,
  metatable_offset = ffi.offsetof("SponTestTable", "metatable"),
  field_offset = ffi.offsetof("SponTestTable", "field0"),
  slots = { [0] = 1, [1] = 0, [2] = 2 },
}
local table_keepalive = {}

local getfield = lower_native({ { op = "GETFIELD", a = 1, b = 0, c = 2 } }, field_facts(false))
assert_true((function()
  local roles = {}
  for _, dr in ipairs(getfield.data_relocs or {}) do roles[dr.role_kind] = true end
  return roles.shape_offset and roles.shape_id and roles.metatable_offset and roles.field_offset
end)(), "GETFIELD must expose table payload relocs")
run_native(getfield,
  function(buf, f) patch_payloads(buf, f, field_payload) end,
  function(ctx, stack)
    local t = ffi.new("SponTestTable[1]")
    table_keepalive.getfield = t
    t[0].shape_id = field_payload.shape_id
    t[0].metatable = nil
    t[0].field0.value_ = 77
    t[0].field0.tt_ = 3
    stack[0].value_ = ptr_u64(t)
    stack[0].tt_ = 69 -- collectable LUA_VTABLE
    ctx.exit_kind = 99
  end,
  function(ctx, stack)
    assert_eq(tonumber(ctx.exit_kind), 0, "GETFIELD exit")
    assert_eq(tonumber(stack[1].value_), 77, "GETFIELD value")
    assert_eq(tonumber(stack[1].tt_), 3, "GETFIELD tag")
  end)
run_native(getfield,
  function(buf, f) patch_payloads(buf, f, field_payload) end,
  function(ctx, stack)
    local t = ffi.new("SponTestTable[1]")
    table_keepalive.getfield_fail = t
    t[0].shape_id = 0
    t[0].metatable = nil
    t[0].field0.value_ = 77
    t[0].field0.tt_ = 3
    stack[0].value_ = ptr_u64(t)
    stack[0].tt_ = 69
    stack[1].value_ = 0
    stack[1].tt_ = 0
    ctx.exit_kind = 99
  end,
  function(ctx, stack)
    assert_eq(tonumber(ctx.exit_kind), 1, "GETFIELD shape guard exit")
    assert_eq(tonumber(ctx.exit_pc), 1, "GETFIELD guard pc")
    assert_eq(tonumber(stack[1].tt_), 0, "GETFIELD failed guard must not store")
  end)

local setfield = lower_native({ { op = "SETFIELD", a = 0, b = 2, c = 1 } }, field_facts(true))
local setfield_payload = {}
for k, v in pairs(field_payload) do setfield_payload[k] = v end
setfield_payload.slots = { [0] = 0, [1] = 1 }
run_native(setfield,
  function(buf, f) patch_payloads(buf, f, setfield_payload) end,
  function(ctx, stack)
    local t = ffi.new("SponTestTable[1]")
    table_keepalive.setfield = t
    ctx.scratch[0].value_ = ptr_u64(t)
    t[0].shape_id = field_payload.shape_id
    t[0].metatable = nil
    t[0].field0.value_ = 0
    t[0].field0.tt_ = 0
    stack[0].value_ = ptr_u64(t)
    stack[0].tt_ = 69
    stack[1].value_ = 88
    stack[1].tt_ = 3
    ctx.exit_kind = 99
  end,
  function(ctx)
    local t = ffi.cast("SponTestTable *", ffi.cast("uintptr_t", ctx.scratch[0].value_))
    assert_eq(tonumber(ctx.exit_kind), 0, "SETFIELD exit")
    assert_eq(tonumber(t[0].field0.value_), 88, "SETFIELD value")
    assert_eq(tonumber(t[0].field0.tt_), 3, "SETFIELD tag")
  end)

local self_stencil = lower_native({ { op = "SELF", a = 1, b = 0, c = 2 } }, field_facts(false))
run_native(self_stencil,
  function(buf, f) patch_payloads(buf, f, field_payload) end,
  function(ctx, stack)
    local t = ffi.new("SponTestTable[1]")
    table_keepalive.self = t
    t[0].shape_id = field_payload.shape_id
    t[0].metatable = nil
    t[0].field0.value_ = 0xfeed
    t[0].field0.tt_ = 3
    stack[0].value_ = ptr_u64(t)
    stack[0].tt_ = 69
    ctx.exit_kind = 99
  end,
  function(ctx, stack)
    assert_eq(tonumber(ctx.exit_kind), 0, "SELF exit")
    assert_eq(tonumber(stack[1].value_), 0xfeed, "SELF method value")
    assert_eq(tonumber(stack[1].tt_), 3, "SELF method tag")
    assert_eq(tonumber(stack[2].tt_), 69, "SELF receiver tag")
  end)

local unsupported = SSA.compile({ { op = "GETUPVAL", a = 0, b = 0 } }, {})
assert_true(not unsupported.ok, "GETUPVAL must remain explicit missing coverage")
local unsupported_table = SSA.compile({ { op = "GETTABLE", a = 0, b = 0, c = 1 } }, {})
assert_true(not unsupported_table.ok, "GETTABLE without table/array payload facts must remain explicit missing coverage")
local unsupported_pow = SSA.compile({ { op = "POW", a = 0, b = 0, c = 1 } }, { Facts.fact("type", Facts.slot("R0"), "is_i64", true), Facts.fact("type", Facts.slot("R1"), "is_i64", true) })
assert_true(not unsupported_pow.ok, "POW must remain unsupported until exact Lua pow semantics exist")

print("ok - SpongeJIT native stencil bytes execute")

