enum {
  SPON_OP_MOVE = 0,
  SPON_OP_LOADI = 1,
  SPON_OP_LOADF = 2,
  SPON_OP_LOADK = 3,
  SPON_OP_LOADKX = 4,
  SPON_OP_LOADFALSE = 5,
  SPON_OP_LFALSESKIP = 6,
  SPON_OP_LOADTRUE = 7,
  SPON_OP_LOADNIL = 8,
  SPON_OP_GETFIELD = 14,
  SPON_OP_SETFIELD = 18,
  SPON_OP_SELF = 20,
  SPON_OP_ADDI = 21,
  SPON_OP_MODK = 25,
  SPON_OP_DIVK = 27,
  SPON_OP_IDIVK = 28,
  SPON_OP_SHLI = 32,
  SPON_OP_SHRI = 33,
  SPON_OP_MOD = 37,
  SPON_OP_DIV = 39,
  SPON_OP_IDIV = 40
};

enum {
  SPON_LUA_VNIL = 0,
  SPON_LUA_VFALSE = 1,
  SPON_LUA_VNUMINT = 3,
  SPON_LUA_VTRUE = 17,
  SPON_LUA_VNUMFLT = 19
};

#define SPON_FACT_I64_SLOT(slot_) (((SponFactSig)1) << (slot_))

typedef struct SponL1Op {
  uint32_t opcode;
  int32_t a;
  int32_t b;
  int32_t c;
  int32_t bx;
  int32_t ax;
  int32_t sbx;
  int32_t sj;
